  1→//! Configuration view and validation commands — `forge config`.
  2→
  3→use anyhow::Result;
  4→
  5→use super::super::ConfigCommands;
  6→
  7→pub fn cmd_config(project_dir: &std::path::Path, command: Option<ConfigCommands>) -> Result<()> {
  8→    use forge::forge_config::{ForgeConfig, ForgeToml};
  9→    use forge::init::get_forge_dir;
 10→
 11→    let forge_dir = get_forge_dir(project_dir);
 12→    let config_path = forge_dir.join("forge.toml");
 13→
 14→    match command {
 15→        None | Some(ConfigCommands::Show) => {
 16→            // Show current configuration
 17→            println!();
 18→            println!("Forge Configuration");
 19→            println!("===================");
 20→            println!();
 21→
 22→            if config_path.exists() {
 23→                println!("Config file: {}", config_path.display());
 24→                println!();
 25→
 26→                let toml = ForgeToml::load(&config_path)?;
 27→
 28→                // Project section
 29→                if toml.project.name.is_some() || toml.project.claude_cmd.is_some() {
 30→                    println!("[project]");
 31→                    if let Some(name) = &toml.project.name {
 32→                        println!("  name = \"{}\"", name);
 33→                    }
 34→                    if let Some(cmd) = &toml.project.claude_cmd {
 35→                        println!("  claude_cmd = \"{}\"", cmd);
 36→                    }
 37→                    println!();
 38→                }
 39→
 40→                // Defaults section
 41→                println!("[defaults]");
 42→                println!("  budget = {}", toml.defaults.budget);
 43→                println!(
 44→                    "  auto_approve_threshold = {}",
 45→                    toml.defaults.auto_approve_threshold
 46→                );
 47→                println!("  permission_mode = \"{}\"", toml.defaults.permission_mode);
 48→                println!("  context_limit = \"{}\"", toml.defaults.context_limit);
 49→                println!("  skip_permissions = {}", toml.defaults.skip_permissions);
 50→                println!();
 51→
 52→                // Phase overrides
 53→                if !toml.phases.overrides.is_empty() {
 54→                    println!("[phases.overrides]");
 55→                    for (pattern, override_cfg) in &toml.phases.overrides {
 56→                        println!("  \"{}\":", pattern);
 57→                        if let Some(budget) = override_cfg.budget {
 58→                            println!("    budget = {}", budget);
 59→                        }
 60→                        if let Some(mode) = override_cfg.permission_mode {
 61→                            println!("    permission_mode = \"{}\"", mode);
 62→                        }
 63→                        if let Some(limit) = &override_cfg.context_limit {
 64→                            println!("    context_limit = \"{}\"", limit);
 65→                        }
 66→                    }
 67→                    println!();
 68→                }
 69→
 70→                // Show effective values (including env overrides)
 71→                println!("Effective values (with env/CLI overrides):");
 72→                let config = ForgeConfig::new(project_dir.to_path_buf())?;
 73→                println!("  claude_cmd = \"{}\"", config.claude_cmd());
 74→                println!("  skip_permissions = {}", config.skip_permissions());
 75→                println!();
 76→            } else {
 77→                println!("No forge.toml found at {}", config_path.display());
 78→                println!();
 79→                println!("Using default configuration:");
 80→                let toml = ForgeToml::default();
 81→                println!("  budget = {}", toml.defaults.budget);
 82→                println!(
 83→                    "  auto_approve_threshold = {}",
 84→                    toml.defaults.auto_approve_threshold
 85→                );
 86→                println!("  permission_mode = \"{}\"", toml.defaults.permission_mode);
 87→                println!("  context_limit = \"{}\"", toml.defaults.context_limit);
 88→                println!("  skip_permissions = {}", toml.defaults.skip_permissions);
 89→                println!();
 90→                println!("Run 'forge config init' to create a forge.toml file.");
 91→                println!();
 92→            }
 93→        }
 94→        Some(ConfigCommands::Validate) => {
 95→            // Validate configuration
 96→            println!();
 97→            println!("Validating configuration...");
 98→            println!();
 99→
100→            if !config_path.exists() {
101→                println!("No forge.toml found. Using defaults (valid).");
102→                return Ok(());
103→            }
104→
105→            let toml = ForgeToml::load(&config_path)?;
106→            let warnings = toml.validate();
107→
108→            if warnings.is_empty() {
109→                println!("Configuration is valid.");
110→            } else {
111→                println!("Configuration warnings:");
112→                for warning in warnings {
113→                    println!("  - {}", warning);
114→                }
115→            }
116→            println!();
117→        }
118→        Some(ConfigCommands::Init) => {
119→            // Initialize default forge.toml
120→            if config_path.exists() {
121→                println!("forge.toml already exists at {}", config_path.display());
122→                println!("Delete it first if you want to recreate it.");
123→                return Ok(());
124→            }
125→
126→            // Ensure .forge directory exists
127→            if !forge_dir.exists() {
128→                std::fs::create_dir_all(&forge_dir)?;
129→            }
130→
131→            let toml = ForgeToml::default();
132→            toml.save(&config_path)?;
133→
134→            println!("Created forge.toml at {}", config_path.display());
135→            println!();
136→            println!("You can now customize:");
137→            println!("  - [project] name, claude_cmd");
138→            println!("  - [defaults] budget, permission_mode, context_limit");
139→            println!("  - [phases.overrides.\"pattern-*\"] for phase-specific settings");
140→            println!();
141→        }
142→    }
143→
144→    Ok(())
145→}
