 1→//! Factory Kanban UI server command — `forge factory`.
 2→
 3→use anyhow::Result;
 4→use tracing::warn;
 5→
 6→pub async fn cmd_factory(
 7→    port: u16,
 8→    init: bool,
 9→    db_path: std::path::PathBuf,
10→    open: bool,
11→    dev: bool,
12→) -> Result<()> {
13→    if init {
14→        // Just initialize the database (creates + runs migrations)
15→        if let Some(parent) = db_path.parent() {
16→            std::fs::create_dir_all(parent)?;
17→        }
18→        forge::factory::db::DbHandle::new_local(&db_path).await?;
19→        println!("Factory database initialized at {}", db_path.display());
20→        return Ok(());
21→    }
22→
23→    // Spawn browser open before starting the server (which blocks)
24→    // Skip in dev mode (no browser inside Docker containers)
25→    if open && !dev {
26→        let url = format!("http://localhost:{}", port);
27→        tokio::spawn(async move {
28→            // Small delay to let the server start binding
29→            tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
30→            if let Err(e) = open::that(&url) {
31→                warn!("Failed to open browser: {}", e);
32→            }
33→        });
34→    }
35→
36→    let project_path = std::env::current_dir()
37→        .map(|p| p.to_string_lossy().to_string())
38→        .unwrap_or_else(|_| ".".to_string());
39→
40→    forge::factory::server::start_server(forge::factory::server::ServerConfig {
41→        port,
42→        db_path,
43→        project_path,
44→        dev_mode: dev,
45→    })
46→    .await?;
47→
48→    Ok(())
