  1→//! Typed error hierarchy for the Forge orchestrator.
  2→//!
  3→//! Three top-level enums cover the three subsystems:
  4→//! - `OrchestratorError` — sequential and DAG runner failures
  5→//! - `PhaseError` — per-phase execution failures
  6→//! - `FactoryError` — factory API and pipeline failures
  7→
  8→use thiserror::Error;
  9→
 10→/// Errors from the orchestrator subsystem (sequential and DAG runners).
 11→#[derive(Debug, Error)]
 12→pub enum OrchestratorError {
 13→    #[error("Failed to spawn Claude process: {0}")]
 14→    SpawnFailed(#[source] std::io::Error),
 15→
 16→    #[error("Failed to write prompt file at {path}: {source}")]
 17→    PromptWriteFailed {
 18→        path: std::path::PathBuf,
 19→        #[source]
 20→        source: std::io::Error,
 21→    },
 22→
 23→    #[error("Failed to write output file at {path}: {source}")]
 24→    OutputWriteFailed {
 25→        path: std::path::PathBuf,
 26→        #[source]
 27→        source: std::io::Error,
 28→    },
 29→
 30→    #[error("Failed to read spec file at {path}: {source}")]
 31→    SpecReadFailed {
 32→        path: std::path::PathBuf,
 33→        #[source]
 34→        source: std::io::Error,
 35→    },
 36→
 37→    #[error("Git tracker error: {0}")]
 38→    GitTracker(String),
 39→
 40→    #[error(transparent)]
 41→    Other(#[from] anyhow::Error),
 42→}
 43→
 44→/// Errors from a single phase execution.
 45→#[derive(Debug, Error)]
 46→pub enum PhaseError {
 47→    #[error("Budget exhausted after {iterations} iterations without promise tag")]
 48→    BudgetExhausted { iterations: u32 },
 49→
 50→    #[error("Claude exited with non-zero code {exit_code}")]
 51→    ClaudeNonZeroExit { exit_code: i32 },
 52→
 53→    #[error("Phase {phase} depends on unknown phase {dependency}")]
 54→    UnknownDependency { phase: String, dependency: String },
 55→
 56→    #[error("Iteration {iteration} failed: {message}")]
 57→    IterationFailed { iteration: u32, message: String },
 58→
 59→    #[error(transparent)]
 60→    Orchestrator(#[from] OrchestratorError),
 61→}
 62→
 63→/// Errors from the factory API and pipeline subsystem.
 64→#[derive(Debug, Error)]
 65→pub enum FactoryError {
 66→    #[error("Project {id} not found")]
 67→    ProjectNotFound { id: i64 },
 68→
 69→    #[error("Issue {id} not found")]
 70→    IssueNotFound { id: i64 },
 71→
 72→    #[error("Pipeline run {id} not found")]
 73→    RunNotFound { id: i64 },
 74→
 75→    #[error("Database error: {0}")]
 76→    Database(#[source] anyhow::Error),
 77→
 78→    #[error("Database lock poisoned")]
 79→    LockPoisoned,
 80→
 81→    #[error("GitHub API error: {0}")]
 82→    GitHub(String),
 83→
 84→    #[error("Invalid column '{column}': {message}")]
 85→    InvalidColumn { column: String, message: String },
 86→
 87→    #[error("Pipeline already running for issue {issue_id}")]
 88→    PipelineAlreadyRunning { issue_id: i64 },
 89→
 90→    #[error("Invalid request: {0}")]
 91→    BadRequest(String),
 92→
 93→    #[error(transparent)]
 94→    Other(#[from] anyhow::Error),
 95→}
