#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt()
        .with_env_filter(EnvFilter::from_default_env())
        .with_target(false)
        .with_thread_ids(false)
        .init();

    let cli = Cli::parse();
    let project_dir = match cli.project_dir.clone() {
        Some(dir) => dir,
        None => std::env::current_dir().context("Failed to get current directory")?,
    };

    // Initialize telemetry (logging + tracing)
    let log_level = cli
        .log_level
        .clone()
        .or_else(|| std::env::var("FORGE_LOG").ok())
        .unwrap_or_else(|| {
            if cli.verbose {
                "debug".to_string()
            } else {
                "warn".to_string()
            }
        });
    let log_format = cli.log_format.clone().or_else(|| {
        std::env::var("FORGE_LOG_FORMAT")
            .ok()
            .and_then(|s| match s.to_lowercase().as_str() {
                "json" => Some(forge::telemetry::LogFormat::Json),
                "compact" => Some(forge::telemetry::LogFormat::Compact),
                _ => {
                    eprintln!(
                        "[forge] Warning: unknown FORGE_LOG_FORMAT '{}', ignoring",
                        s
                    );
                    None
                }
            })
    });
    let otlp_endpoint = cli
        .otlp_endpoint
        .clone()
        .or_else(|| std::env::var("FORGE_OTLP_ENDPOINT").ok());
    let forge_dir = project_dir.join(".forge");
    // Avoid creating `.forge/` as a side effect before `forge init` runs.
    let log_dir = if forge::init::is_initialized(&project_dir) {
        forge_dir.join("logs")
    } else {
        std::env::temp_dir().join("forge-logs")
    };
    if let Err(e) = forge::telemetry::init_telemetry(&forge::telemetry::TelemetryConfig {
        log_level,
        log_format,
        log_dir,
        otlp_endpoint,
    }) {
        eprintln!("[forge] Warning: failed to initialize telemetry: {:#}", e);
    }

    match &cli.command {
        Commands::Init { from } => {
            cmd::cmd_init(&project_dir, from.as_deref())?;
        }
        Commands::Interview => {
            cmd::cmd_interview(&project_dir)?;
        }
        Commands::Generate => {
            cmd::cmd_generate(&project_dir, cli.spec_file.as_deref(), cli.yes)?;
        }
        Commands::Run { phase } => {
            cmd::run_orchestrator(&cli, project_dir, phase.clone()).await?;
        }
        Commands::Phase { number } => {
            cmd::run_single_phase(&cli, project_dir, number).await?;
        }
        Commands::List => cmd::cmd_list(&project_dir)?,
        Commands::Status => cmd::cmd_status(&project_dir)?,
        Commands::Reset { force } => cmd::cmd_reset(&project_dir, &cli, *force)?,
        Commands::Audit { command } => cmd::cmd_audit(&project_dir, command)?,
        Commands::Learn { name } => cmd::cmd_learn(&project_dir, name.as_deref())?,
        Commands::Patterns { command } => cmd::cmd_patterns(command.clone())?,
        Commands::Config { command } => cmd::cmd_config(&project_dir, command.clone())?,
        Commands::Skills { command } => cmd::cmd_skills(&project_dir, command.clone())?,
        Commands::Compact { phase, status } => {
            cmd::cmd_compact(&project_dir, &cli, phase.as_deref(), *status)?
        }
        Commands::Implement {
            design_doc,
            no_tdd,
            start_phase,
            dry_run,
        } => {
            if let Some(start) = start_phase {
                // Verify phases exist before resuming
                let phases_path = project_dir.join(".forge").join("phases.json");
                if !phases_path.exists() {
                    anyhow::bail!(
                        "Cannot resume from phase {}: No phases.json found. Run 'forge implement <design-doc>' first.",
                        start
                    );
                }
                cmd::run_orchestrator(&cli, project_dir, Some(start.clone())).await?;
            } else {
                cmd::cmd_implement(&project_dir, design_doc, *no_tdd, *dry_run)?;
            }
        }
        Commands::Factory {
            port,
            init,
            db_path,
            open,
            dev,
        } => {
            let db_path = std::path::PathBuf::from(&db_path);
            cmd::cmd_factory(*port, *init, db_path, *open, *dev).await?;
        }
        Commands::Swarm {
            command,
            from,
            only,
            max_parallel,
            backend,
            review,
            review_mode,
            max_fix_attempts,
            escalate_on,
            arbiter_confidence,
            decompose,
            no_decompose,
            decompose_threshold,
            permission_mode,
            ui,
            fail_fast,
        } => {
            // Handle subcommands first
            if let Some(subcmd) = command {
                match subcmd {
                    SwarmCommands::Status => {
                        cmd::cmd_swarm_status(&project_dir)?;
                        return Ok(());
                    }
                    SwarmCommands::Abort => {
                        cmd::cmd_swarm_abort(&project_dir)?;
                        return Ok(());
                    }
                }
            }

            // Main swarm execution
            cmd::cmd_swarm(
                &project_dir,
                &cli,
                from.as_deref(),
                only.as_deref(),
                *max_parallel,
                backend,
                review.as_deref(),
                review_mode,
                *max_fix_attempts,
                escalate_on.as_deref(),
                *arbiter_confidence,
                *decompose && !*no_decompose,
                *decompose_threshold,
                permission_mode,
                ui,
                *fail_fast,
            )
            .await?;
        }
    }

    Ok(())
}

