307→/// Current binary version from Cargo.toml.
308→pub const VERSION: &str = env!("CARGO_PKG_VERSION");
309→
310→/// Spawn a non-blocking background version check.
311→/// Prints a notification after the main command completes if a newer version exists.
312→/// All errors are silently swallowed — this must never interfere with normal operation.
313→pub async fn maybe_notify_update() {
314→    if let Err(_) = try_notify_update().await {}
315→}
316→
317→async fn try_notify_update() -> Result<()> {
318→    let forge_dir = global_forge_dir()?;
319→    let config = load_update_config(&forge_dir)?;
320→
321→    // Check cache first
322→    if let Some(cache) = read_cache(&forge_dir)? {
323→        if is_cache_fresh(&cache, config.check_interval) {
324→            if is_newer(VERSION, &cache.latest_version) {
325→                print_update_notice(&cache.latest_version);
326→            }
327→            return Ok(());
328→        }
329→    }
330→
331→    // Fetch latest from GitHub (with timeout)
332→    let client = reqwest::Client::builder()
333→        .timeout(std::time::Duration::from_secs(5))
334→        .build()?;
335→    let resp = client
336→        .get("https://api.github.com/repos/jdsingh122918/forge/releases/latest")
337→        .header("User-Agent", "forge-update-check")
338→        .send()
339→        .await?;
340→
341→    if !resp.status().is_success() {
342→        return Ok(()); // Silently ignore API errors (rate limit, etc.)
343→    }
344→
345→    let body: serde_json::Value = resp.json().await?;
346→    let tag = body["tag_name"]
347→        .as_str()
348→        .ok_or_else(|| anyhow::anyhow!("missing tag_name"))?;
349→    let latest = tag.strip_prefix('v').unwrap_or(tag);
350→
351→    // Write cache
352→    let now = std::time::SystemTime::now()
353→        .duration_since(std::time::UNIX_EPOCH)?
354→        .as_secs();
355→    write_cache(
356→        &forge_dir,
357→        &UpdateCache {
358→            timestamp: now,
359→            latest_version: latest.to_string(),
360→        },
361→    )?;
362→
363→    if is_newer(VERSION, latest) {
364→        print_update_notice(latest);
365→    }
366→
367→    Ok(())
368→}
369→
370→fn print_update_notice(latest: &str) {
371→    eprintln!(
372→        "\nA new version of forge is available: v{} (current: v{})",
373→        latest, VERSION
374→    );
375→    eprintln!("Run `forge update` to upgrade.\n");
376→}
