404→//! Self-update command — `forge update`.
405→
406→use anyhow::{Context, Result};
407→
408→/// Build-time target triple. Assembled from cfg! macros so the binary
409→/// knows which release asset to download.
410→pub const TARGET: &str = {
411→    #[cfg(all(target_arch = "x86_64", target_os = "macos"))]
412→    { "x86_64-apple-darwin" }
413→    #[cfg(all(target_arch = "aarch64", target_os = "macos"))]
414→    { "aarch64-apple-darwin" }
415→    #[cfg(all(target_arch = "x86_64", target_os = "linux"))]
416→    { "x86_64-unknown-linux-gnu" }
417→    #[cfg(all(target_arch = "aarch64", target_os = "linux"))]
418→    { "aarch64-unknown-linux-gnu" }
419→    #[cfg(not(any(
420→        all(target_arch = "x86_64", target_os = "macos"),
421→        all(target_arch = "aarch64", target_os = "macos"),
422→        all(target_arch = "x86_64", target_os = "linux"),
423→        all(target_arch = "aarch64", target_os = "linux"),
424→    )))]
425→    { "unknown" }
426→};
427→
428→pub async fn cmd_update(check_only: bool, force: bool) -> Result<()> {
429→    let current = forge::update_check::VERSION;
430→
431→    if check_only {
432→        return check_and_print().await;
433→    }
434→
435→    println!("Forge v{} ({})", current, TARGET);
436→    println!("Checking for updates...");
437→
438→    let status = self_update::backends::github::Update::configure()
439→        .repo_owner("jdsingh122918")
440→        .repo_name("forge")
441→        .bin_name("forge")
442→        .target(TARGET)
443→        .asset_regex(&format!("forge-{}\\.tar\\.gz", regex::escape(TARGET)))
444→        .current_version(current)
445→        .no_confirm(true)
446→        .build()
447→        .context("Failed to configure updater")?
448→        .update()
449→        .context("Update failed")?;
450→
451→    if status.updated() || force {
452→        println!("Updated forge from v{} -> v{}", current, status.version());
453→    } else {
454→        println!("Already on the latest version (v{}).", current);
455→    }
456→
457→    // Clear the update cache so the startup check doesn't show a stale notice
458→    if let Ok(forge_dir) = forge::update_check::global_forge_dir() {
459→        let cache_path = forge_dir.join("last-update-check");
460→        let _ = std::fs::remove_file(cache_path);
461→    }
462→
463→    Ok(())
464→}
465→
466→async fn check_and_print() -> Result<()> {
467→    let current = forge::update_check::VERSION;
468→
469→    let client = reqwest::Client::builder()
470→        .timeout(std::time::Duration::from_secs(10))
471→        .build()?;
472→    let resp = client
473→        .get("https://api.github.com/repos/jdsingh122918/forge/releases/latest")
474→        .header("User-Agent", "forge-update-check")
475→        .send()
476→        .await
477→        .context("Failed to reach GitHub API")?;
478→
479→    if !resp.status().is_success() {
480→        anyhow::bail!("GitHub API returned {}", resp.status());
481→    }
482→
483→    let body: serde_json::Value = resp.json().await?;
484→    let tag = body["tag_name"]
485→        .as_str()
486→        .ok_or_else(|| anyhow::anyhow!("missing tag_name in response"))?;
487→    let latest = tag.strip_prefix('v').unwrap_or(tag);
488→
489→    if forge::update_check::is_newer(current, latest) {
490→        println!("Update available: v{} -> v{}", current, latest);
491→        println!("Run `forge update` to upgrade.");
492→    } else {
493→        println!("You're on the latest version (v{}).", current);
494→    }
495→
496→    Ok(())
497→}
