755→detect_platform() {
756→    OS=$(uname -s)
757→    ARCH=$(uname -m)
758→
759→    case "$OS" in
760→        Darwin) ;;
761→        Linux) ;;
762→        *)
763→            echo "Error: Unsupported OS: $OS"
764→            echo "Forge supports macOS and Linux."
765→            exit 1
766→            ;;
767→    esac
768→
769→    case "$ARCH" in
770→        x86_64|amd64) ARCH="x86_64" ;;
771→        arm64|aarch64) ARCH="aarch64" ;;
772→        *)
773→            echo "Error: Unsupported architecture: $ARCH"
774→            exit 1
775→            ;;
776→    esac
777→
778→    case "${OS}-${ARCH}" in
779→        Darwin-x86_64)  TARGET="x86_64-apple-darwin" ;;
780→        Darwin-aarch64) TARGET="aarch64-apple-darwin" ;;
781→        Linux-x86_64)   TARGET="x86_64-unknown-linux-gnu" ;;
782→        Linux-aarch64)  TARGET="aarch64-unknown-linux-gnu" ;;
783→        *)
