793→    if [ -n "${FORGE_VERSION:-}" ]; then
794→        VERSION="$FORGE_VERSION"
795→        echo "Installing pinned version: ${VERSION}"
796→    else
797→        echo "Fetching latest release..."
798→        VERSION=$(curl -sSf "https://api.github.com/repos/${REPO}/releases/latest" \
799→            | grep '"tag_name"' \
800→            | sed 's/.*"tag_name": *"\([^"]*\)".*/\1/')
801→
802→        if [ -z "$VERSION" ]; then
803→            echo "Error: Could not determine latest version."
804→            echo "Check https://github.com/${REPO}/releases"
805→            exit 1
806→        fi
807→        echo "Latest version: ${VERSION}"
808→    fi
809→}
810→
811→download_and_verify() {
812→    ARCHIVE="forge-${TARGET}.tar.gz"
813→    URL="https://github.com/${REPO}/releases/download/${VERSION}/${ARCHIVE}"
814→    CHECKSUMS_URL="https://github.com/${REPO}/releases/download/${VERSION}/sha256sums.txt"
815→
816→    TMPDIR=$(mktemp -d)
817→    trap 'rm -rf "$TMPDIR"' EXIT
818→
819→    echo "Downloading ${ARCHIVE}..."
820→    curl -sSfL -o "${TMPDIR}/${ARCHIVE}" "$URL" || {
821→        echo "Error: Failed to download ${URL}"
822→        echo "Check that version ${VERSION} exists at https://github.com/${REPO}/releases"
823→        exit 1
824→    }
825→
826→    echo "Downloading checksums..."
827→    curl -sSfL -o "${TMPDIR}/sha256sums.txt" "$CHECKSUMS_URL" || {
828→        echo "Error: Failed to download checksums."
829→        exit 1
830→    }
831→
832→    echo "Verifying checksum..."
833→    EXPECTED=$(grep "${ARCHIVE}" "${TMPDIR}/sha256sums.txt" | awk '{print $1}')
834→    if [ -z "$EXPECTED" ]; then
835→        echo "Error: Archive not found in checksums file."
836→        exit 1
837→    fi
838→
839→    if command -v sha256sum >/dev/null 2>&1; then
840→        ACTUAL=$(sha256sum "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
841→    elif command -v shasum >/dev/null 2>&1; then
842→        ACTUAL=$(shasum -a 256 "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
843→    else
844→        echo "Warning: No sha256sum or shasum found, skipping verification."
845→        ACTUAL="$EXPECTED"
846→    fi
847→
848→    if [ "$EXPECTED" != "$ACTUAL" ]; then
849→        echo "Error: Checksum verification failed!"
850→        echo "  Expected: ${EXPECTED}"
851→        echo "  Actual:   ${ACTUAL}"
852→        exit 1
853→    fi
854→    echo "Checksum verified."
855→
856→    echo "Extracting..."
857→    tar xzf "${TMPDIR}/${ARCHIVE}" -C "${TMPDIR}"
858→}
