 70→//! Background version check and update configuration.
 71→
 72→use anyhow::Result;
 73→use serde::{Deserialize, Serialize};
 74→use std::path::{Path, PathBuf};
 75→
 76→/// Update preferences from ~/.forge/config.toml [update] section.
 77→#[derive(Debug, Clone, Serialize, Deserialize)]
 78→pub struct UpdateConfig {
 79→    /// Silently auto-update on startup. Default: false.
 80→    #[serde(default)]
 81→    pub auto: bool,
 82→    /// Hours between version checks. Default: 24.
 83→    #[serde(default = "default_check_interval")]
 84→    pub check_interval: u64,
 85→}
 86→
 87→fn default_check_interval() -> u64 {
 88→    24
 89→}
 90→
 91→impl Default for UpdateConfig {
 92→    fn default() -> Self {
 93→        Self {
 94→            auto: false,
 95→            check_interval: default_check_interval(),
 96→        }
 97→    }
 98→}
 99→
100→/// Cached result of the last version check.
101→#[derive(Debug, Serialize, Deserialize)]
102→pub struct UpdateCache {
103→    /// Unix timestamp of last check.
104→    pub timestamp: u64,
105→    /// Latest version seen (without "v" prefix).
106→    pub latest_version: String,
107→}
108→
109→/// Returns the global forge config directory (~/.forge/).
110→pub fn global_forge_dir() -> Result<PathBuf> {
111→    let home = dirs::home_dir().ok_or_else(|| anyhow::anyhow!("Cannot determine home directory"))?;
112→    Ok(home.join(".forge"))
113→}
114→
115→/// Load update config from ~/.forge/config.toml.
116→/// Returns defaults if file or [update] section is missing.
117→pub fn load_update_config(forge_dir: &Path) -> Result<UpdateConfig> {
118→    let config_path = forge_dir.join("config.toml");
119→    if !config_path.exists() {
120→        return Ok(UpdateConfig::default());
121→    }
122→    let content = std::fs::read_to_string(&config_path)?;
123→    let table: toml::Table = content.parse()?;
124→    match table.get("update") {
125→        Some(section) => {
126→            let config: UpdateConfig = section.clone().try_into()?;
127→            Ok(config)
128→        }
129→        None => Ok(UpdateConfig::default()),
130→    }
131→}
132→
133→/// Read the update cache from ~/.forge/last-update-check.
134→pub fn read_cache(forge_dir: &Path) -> Result<Option<UpdateCache>> {
135→    let cache_path = forge_dir.join("last-update-check");
136→    if !cache_path.exists() {
137→        return Ok(None);
138→    }
139→    let content = std::fs::read_to_string(&cache_path)?;
140→    let cache: UpdateCache = serde_json::from_str(&content)?;
141→    Ok(Some(cache))
142→}
143→
144→/// Write the update cache to ~/.forge/last-update-check.
145→pub fn write_cache(forge_dir: &Path, cache: &UpdateCache) -> Result<()> {
146→    let cache_path = forge_dir.join("last-update-check");
147→    std::fs::create_dir_all(forge_dir)?;
148→    let content = serde_json::to_string(cache)?;
149→    std::fs::write(&cache_path, content)?;
150→    Ok(())
151→}
152→
153→/// Returns true if the cache is fresh (within check_interval hours).
154→pub fn is_cache_fresh(cache: &UpdateCache, check_interval_hours: u64) -> bool {
155→    let now = std::time::SystemTime::now()
156→        .duration_since(std::time::UNIX_EPOCH)
157→        .unwrap_or_default()
158→        .as_secs();
159→    let age_secs = now.saturating_sub(cache.timestamp);
160→    age_secs < check_interval_hours * 3600
161→}
162→
163→/// Compare two semver version strings. Returns true if `latest` is newer than `current`.
164→pub fn is_newer(current: &str, latest: &str) -> bool {
165→    let parse = |s: &str| -> Option<(u64, u64, u64)> {
166→        let s = s.strip_prefix('v').unwrap_or(s);
167→        let parts: Vec<&str> = s.split('.').collect();
168→        if parts.len() != 3 {
169→            return None;
170→        }
171→        Some((
172→            parts[0].parse().ok()?,
173→            parts[1].parse().ok()?,
174→            parts[2].parse().ok()?,
175→        ))
176→    };
177→    match (parse(current), parse(latest)) {
178→        (Some(c), Some(l)) => l > c,
179→        _ => false,
180→    }
181→}
