733→- [ ] **Step 1: Create install.sh**
734→
735→```bash
736→#!/usr/bin/env sh
737→set -eu
738→
739→# Forge installer — downloads pre-built binary from GitHub Releases.
740→# Usage: curl -sSf https://raw.githubusercontent.com/jdsingh122918/forge/main/install.sh | sh
741→# Pin a version: FORGE_VERSION=v0.2.0 curl ... | sh
742→
743→REPO="jdsingh122918/forge"
744→INSTALL_DIR="${HOME}/.forge/bin"
745→
746→main() {
747→    detect_platform
748→    get_version
749→    download_and_verify
750→    install_binary
751→    configure_path
752→    print_success
753→}
754→
755→detect_platform() {
756→    OS=$(uname -s)
757→    ARCH=$(uname -m)
758→
759→    case "$OS" in
760→        Darwin) ;;
761→        Linux) ;;
762→        *)
763→            echo "Error: Unsupported OS: $OS"
764→            echo "Forge supports macOS and Linux."
765→            exit 1
766→            ;;
767→    esac
768→
769→    case "$ARCH" in
770→        x86_64|amd64) ARCH="x86_64" ;;
771→        arm64|aarch64) ARCH="aarch64" ;;
772→        *)
773→            echo "Error: Unsupported architecture: $ARCH"
774→            exit 1
775→            ;;
776→    esac
777→
778→    case "${OS}-${ARCH}" in
779→        Darwin-x86_64)  TARGET="x86_64-apple-darwin" ;;
780→        Darwin-aarch64) TARGET="aarch64-apple-darwin" ;;
781→        Linux-x86_64)   TARGET="x86_64-unknown-linux-gnu" ;;
782→        Linux-aarch64)  TARGET="aarch64-unknown-linux-gnu" ;;
783→        *)
784→            echo "Error: Unsupported platform: ${OS}-${ARCH}"
785→            exit 1
786→            ;;
787→    esac
788→
789→    echo "Detected platform: ${TARGET}"
790→}
791→
792→get_version() {
793→    if [ -n "${FORGE_VERSION:-}" ]; then
794→        VERSION="$FORGE_VERSION"
795→        echo "Installing pinned version: ${VERSION}"
796→    else
797→        echo "Fetching latest release..."
798→        VERSION=$(curl -sSf "https://api.github.com/repos/${REPO}/releases/latest" \
799→            | grep '"tag_name"' \
800→            | sed 's/.*"tag_name": *"\([^"]*\)".*/\1/')
801→
802→        if [ -z "$VERSION" ]; then
803→            echo "Error: Could not determine latest version."
804→            echo "Check https://github.com/${REPO}/releases"
805→            exit 1
806→        fi
807→        echo "Latest version: ${VERSION}"
808→    fi
809→}
810→
811→download_and_verify() {
812→    ARCHIVE="forge-${TARGET}.tar.gz"
813→    URL="https://github.com/${REPO}/releases/download/${VERSION}/${ARCHIVE}"
814→    CHECKSUMS_URL="https://github.com/${REPO}/releases/download/${VERSION}/sha256sums.txt"
815→
816→    TMPDIR=$(mktemp -d)
817→    trap 'rm -rf "$TMPDIR"' EXIT
818→
819→    echo "Downloading ${ARCHIVE}..."
820→    curl -sSfL -o "${TMPDIR}/${ARCHIVE}" "$URL" || {
821→        echo "Error: Failed to download ${URL}"
822→        echo "Check that version ${VERSION} exists at https://github.com/${REPO}/releases"
823→        exit 1
824→    }
825→
826→    echo "Downloading checksums..."
827→    curl -sSfL -o "${TMPDIR}/sha256sums.txt" "$CHECKSUMS_URL" || {
828→        echo "Error: Failed to download checksums."
829→        exit 1
830→    }
831→
832→    echo "Verifying checksum..."
833→    EXPECTED=$(grep "${ARCHIVE}" "${TMPDIR}/sha256sums.txt" | awk '{print $1}')
834→    if [ -z "$EXPECTED" ]; then
835→        echo "Error: Archive not found in checksums file."
836→        exit 1
837→    fi
838→
839→    if command -v sha256sum >/dev/null 2>&1; then
840→        ACTUAL=$(sha256sum "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
841→    elif command -v shasum >/dev/null 2>&1; then
842→        ACTUAL=$(shasum -a 256 "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
843→    else
844→        echo "Warning: No sha256sum or shasum found, skipping verification."
845→        ACTUAL="$EXPECTED"
846→    fi
847→
848→    if [ "$EXPECTED" != "$ACTUAL" ]; then
849→        echo "Error: Checksum verification failed!"
850→        echo "  Expected: ${EXPECTED}"
851→        echo "  Actual:   ${ACTUAL}"
852→        exit 1
853→    fi
854→    echo "Checksum verified."
855→
856→    echo "Extracting..."
857→    tar xzf "${TMPDIR}/${ARCHIVE}" -C "${TMPDIR}"
858→}
859→
860→install_binary() {
861→    mkdir -p "$INSTALL_DIR"
862→    mv "${TMPDIR}/forge" "${INSTALL_DIR}/forge"
863→    chmod +x "${INSTALL_DIR}/forge"
864→    echo "Installed to ${INSTALL_DIR}/forge"
865→}
866→
867→configure_path() {
868→    case ":${PATH}:" in
869→        *":${INSTALL_DIR}:"*) return ;; # Already in PATH
870→    esac
871→
872→    EXPORT_LINE="export PATH=\"${INSTALL_DIR}:\$PATH\""
873→    SHELL_NAME=$(basename "${SHELL:-/bin/sh}")
874→
875→    case "$SHELL_NAME" in
876→        zsh)
877→            RC_FILE="${HOME}/.zshrc"
878→            ;;
879→        bash)
880→            # macOS uses .bash_profile for login shells
881→            if [ "$(uname -s)" = "Darwin" ] && [ -f "${HOME}/.bash_profile" ]; then
882→                RC_FILE="${HOME}/.bash_profile"
883→            else
884→                RC_FILE="${HOME}/.bashrc"
885→            fi
886→            ;;
887→        fish)
888→            FISH_CONFIG="${HOME}/.config/fish/config.fish"
889→            if [ -f "$FISH_CONFIG" ] && ! grep -q "${INSTALL_DIR}" "$FISH_CONFIG" 2>/dev/null; then
890→                echo "fish_add_path ${INSTALL_DIR}" >> "$FISH_CONFIG"
891→                echo "Added ${INSTALL_DIR} to ${FISH_CONFIG}"
892→            fi
893→            return
894→            ;;
895→        *)
896→            RC_FILE="${HOME}/.profile"
897→            ;;
898→    esac
899→
900→    if [ -f "$RC_FILE" ] && grep -qF "$INSTALL_DIR" "$RC_FILE" 2>/dev/null; then
901→        return # Already configured
902→    fi
903→
904→    echo "" >> "$RC_FILE"
905→    echo "# Added by Forge installer" >> "$RC_FILE"
906→    echo "$EXPORT_LINE" >> "$RC_FILE"
907→    echo "Added ${INSTALL_DIR} to PATH in ${RC_FILE}"
908→}
909→
910→print_success() {
911→    VERSION_NUM=$("${INSTALL_DIR}/forge" --version 2>/dev/null | awk '{print $2}' || echo "${VERSION}")
912→    echo ""
913→    echo "Forge ${VERSION_NUM} installed successfully!"
914→    echo ""
915→    echo "To get started, run:"
916→    echo "  source ${RC_FILE:-~/.profile}  # or open a new terminal"
917→    echo "  forge --help"
918→    echo ""
919→}
920→
921→main
922→```
