//! Self-update command — `forge update`.

use anyhow::{Context, Result};

/// Build-time target triple. Assembled from cfg! macros so the binary
/// knows which release asset to download.
pub const TARGET: &str = {
    #[cfg(all(target_arch = "x86_64", target_os = "macos"))]
    { "x86_64-apple-darwin" }
    #[cfg(all(target_arch = "aarch64", target_os = "macos"))]
    { "aarch64-apple-darwin" }
    #[cfg(all(target_arch = "x86_64", target_os = "linux"))]
    { "x86_64-unknown-linux-gnu" }
    #[cfg(all(target_arch = "aarch64", target_os = "linux"))]
    { "aarch64-unknown-linux-gnu" }
    #[cfg(not(any(
        all(target_arch = "x86_64", target_os = "macos"),
        all(target_arch = "aarch64", target_os = "macos"),
        all(target_arch = "x86_64", target_os = "linux"),
        all(target_arch = "aarch64", target_os = "linux"),
    )))]
    { "unknown" }
};

pub async fn cmd_update(check_only: bool, force: bool) -> Result<()> {
    let current = forge::update_check::VERSION;

    if check_only {
        return check_and_print().await;
    }

    println!("Forge v{} ({})", current, TARGET);
    println!("Checking for updates...");

    let status = self_update::backends::github::Update::configure()
        .repo_owner("jdsingh122918")
        .repo_name("forge")
        .bin_name("forge")
        .target(TARGET)
        .asset_regex(&format!("forge-{}\\.tar\\.gz", regex::escape(TARGET)))
        .current_version(current)
        .no_confirm(true)
        .build()
        .context("Failed to configure updater")?
        .update()
        .context("Update failed")?;

    if status.updated() || force {
        println!("Updated forge from v{} -> v{}", current, status.version());
    } else {
        println!("Already on the latest version (v{}).", current);
    }

    // Clear the update cache so the startup check doesn't show a stale notice
    if let Ok(forge_dir) = forge::update_check::global_forge_dir() {
        let cache_path = forge_dir.join("last-update-check");
        let _ = std::fs::remove_file(cache_path);
    }

    Ok(())
}

async fn check_and_print() -> Result<()> {
    let current = forge::update_check::VERSION;

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(10))
        .build()?;
    let resp = client
        .get("https://api.github.com/repos/jdsingh122918/forge/releases/latest")
        .header("User-Agent", "forge-update-check")
        .send()
        .await
        .context("Failed to reach GitHub API")?;

    if !resp.status().is_success() {
        anyhow::bail!("GitHub API returned {}", resp.status());
    }

    let body: serde_json::Value = resp.json().await?;
    let tag = body["tag_name"]
        .as_str()
        .ok_or_else(|| anyhow::anyhow!("missing tag_name in response"))?;
    let latest = tag.strip_prefix('v').unwrap_or(tag);

    if forge::update_check::is_newer(current, latest) {
        println!("Update available: v{} -> v{}", current, latest);
        println!("Run `forge update` to upgrade.");
    } else {
        println!("You're on the latest version (v{}).", current);
    }

    Ok(())
}
