 167→pub fn is_newer(current: &str, latest: &str) -> bool {
 168→    let parse = |s: &str| -> Option<(u64, u64, u64)> {
 169→        let s = s.strip_prefix('v').unwrap_or(s);
 170→        let parts: Vec<&str> = s.split('.').collect();
 171→        if parts.len() != 3 {
 172→            return None;
 173→        }
 174→        Some((
 175→            parts[0].parse().ok()?,
 176→            parts[1].parse().ok()?,
 177→            parts[2].parse().ok()?,
 178→        ))
 179→    };
 180→    match (parse(current), parse(latest)) {
 181→        (Some(c), Some(l)) => l > c,
 182→        _ => false,
 183→    }
 184→}
