 310→use fs2::FileExt;
 311→
 312→/// Current binary version from Cargo.toml.
 313→pub const VERSION: &str = env!("CARGO_PKG_VERSION");
 314→
 315→/// Spawn a non-blocking background version check as a concurrent task.
 316→/// Returns a JoinHandle that, when awaited, prints a notification if a newer
 317→/// version exists. The handle should be awaited after the main command completes.
 318→pub fn spawn_update_check() -> tokio::task::JoinHandle<()> {
 319→    tokio::spawn(async {
 320→        let _ = try_update_check().await;
 321→    })
 322→}
 323→
 324→async fn try_update_check() -> Result<()> {
 325→    let forge_dir = global_forge_dir()?;
 326→    let config = load_update_config(&forge_dir)?;
 327→
 328→    // Check cache first — if fresh, skip network call entirely
 329→    if let Some(cache) = read_cache(&forge_dir)? {
 330→        if is_cache_fresh(&cache, config.check_interval) {
 331→            if is_newer(VERSION, &cache.latest_version) {
 332→                if config.auto {
 333→                    try_auto_update(&forge_dir)?;
 334→                } else {
 335→                    print_update_notice(&cache.latest_version);
 336→                }
 337→            }
 338→            return Ok(());
 339→        }
 340→    }
 341→
 342→    // Fetch latest from GitHub (with timeout)
 343→    let latest = fetch_latest_version().await?;
 344→
 345→    // Write cache
 346→    let now = std::time::SystemTime::now()
 347→        .duration_since(std::time::UNIX_EPOCH)?
 348→        .as_secs();
 349→    write_cache(
 350→        &forge_dir,
 351→        &UpdateCache {
 352→            timestamp: now,
 353→            latest_version: latest.clone(),
 354→        },
 355→    )?;
 356→
 357→    if is_newer(VERSION, &latest) {
 358→        if config.auto {
 359→            try_auto_update(&forge_dir)?;
 360→        } else {
 361→            print_update_notice(&latest);
 362→        }
 363→    }
 364→
 365→    Ok(())
 366→}
