 368→/// Fetch the latest release version from GitHub API. Returns version without "v" prefix.
 369→pub async fn fetch_latest_version() -> Result<String> {
 370→    let client = reqwest::Client::builder()
 371→        .timeout(std::time::Duration::from_secs(5))
 372→        .build()?;
 373→    let resp = client
 374→        .get("https://api.github.com/repos/jdsingh122918/forge/releases/latest")
 375→        .header("User-Agent", "forge-update-check")
 376→        .send()
 377→        .await?;
 378→
 379→    if !resp.status().is_success() {
 380→        anyhow::bail!("GitHub API returned {}", resp.status());
 381→    }
 382→
 383→    let body: serde_json::Value = resp.json().await?;
 384→    let tag = body["tag_name"]
 385→        .as_str()
 386→        .ok_or_else(|| anyhow::anyhow!("missing tag_name"))?;
 387→    Ok(tag.strip_prefix('v').unwrap_or(tag).to_string())
 388→}
 389→
 390→/// Attempt auto-update with a lockfile to prevent concurrent updates.
 391→fn try_auto_update(forge_dir: &Path) -> Result<()> {
 392→    let lock_path = forge_dir.join("update.lock");
 393→    std::fs::create_dir_all(forge_dir)?;
 394→    let lock_file = std::fs::File::create(&lock_path)?;
 395→
 396→    // Try to acquire exclusive lock — if another process holds it, skip silently
 397→    if lock_file.try_lock_exclusive().is_err() {
 398→        return Ok(());
 399→    }
 400→
 401→    // Perform the update (self_update handles download + atomic replace)
 402→    let target = crate::cmd_target_triple();
 403→    let result = self_update::backends::github::Update::configure()
 404→        .repo_owner("jdsingh122918")
 405→        .repo_name("forge")
 406→        .bin_name("forge")
 407→        .target(target)
 408→        .current_version(VERSION)
 409→        .no_confirm(true)
 410→        .show_output(false)
 411→        .show_download_progress(false)
 412→        .build()?
 413→        .update();
 414→
 415→    // Release lock (explicit, though drop would also release it)
 416→    let _ = lock_file.unlock();
 417→    let _ = std::fs::remove_file(&lock_path);
 418→
 419→    match result {
 420→        Ok(status) if status.updated() => {
 421→            eprintln!(
 422→                "\nForge auto-updated: v{} -> v{}. The new version will be used on next run.\n",
 423→                VERSION,
 424→                status.version()
 425→            );
 426→        }
 427→        _ => {} // Silently ignore failures
 428→    }
 429→
 430→    Ok(())
 431→}
