 491→```rust
 492→//! Self-update command — `forge update`.
 493→
 494→use anyhow::{Context, Result};
 495→use forge::update_check::{self, TARGET, VERSION};
 496→
 497→pub async fn cmd_update(check_only: bool, force: bool) -> Result<()> {
 498→    if check_only {
 499→        return check_and_print().await;
 500→    }
 501→
 502→    println!("Forge v{} ({})", VERSION, TARGET);
 503→    println!("Checking for updates...");
 504→
 505→    if force {
 506→        // --force: bypass self_update's version comparison by setting current to "0.0.0"
 507→        // so it always downloads the latest release
 508→        let status = self_update::backends::github::Update::configure()
 509→            .repo_owner("jdsingh122918")
 510→            .repo_name("forge")
 511→            .bin_name("forge")
 512→            .target(TARGET)
 513→            .current_version("0.0.0")
 514→            .no_confirm(true)
 515→            .build()
 516→            .context("Failed to configure updater")?
 517→            .update()
 518→            .context("Update failed")?;
 519→
 520→        println!("Re-downloaded forge v{} (forced).", status.version());
 521→    } else {
 522→        let status = self_update::backends::github::Update::configure()
 523→            .repo_owner("jdsingh122918")
 524→            .repo_name("forge")
 525→            .bin_name("forge")
 526→            .target(TARGET)
 527→            .current_version(VERSION)
 528→            .no_confirm(true)
 529→            .build()
 530→            .context("Failed to configure updater")?
 531→            .update()
 532→            .context("Update failed")?;
 533→
 534→        if status.updated() {
 535→            println!("Updated forge from v{} -> v{}", VERSION, status.version());
 536→        } else {
 537→            println!("Already on the latest version (v{}).", VERSION);
 538→        }
 539→    }
 540→
 541→    // Clear the update cache so the startup check doesn't show a stale notice
 542→    if let Ok(forge_dir) = update_check::global_forge_dir() {
 543→        let cache_path = forge_dir.join("last-update-check");
 544→        let _ = std::fs::remove_file(cache_path);
 545→    }
 546→
 547→    Ok(())
 548→}
 549→
 550→async fn check_and_print() -> Result<()> {
 551→    let latest = update_check::fetch_latest_version()
 552→        .await
 553→        .context("Failed to check for updates")?;
 554→
 555→    if update_check::is_newer(VERSION, &latest) {
 556→        println!("Update available: v{} -> v{}", VERSION, latest);
 557→        println!("Run `forge update` to upgrade.");
 558→    } else {
 559→        println!("You're on the latest version (v{}).", VERSION);
 560→    }
 561→
 562→    Ok(())
 563→}
