 828→
 829→```bash
 830→#!/usr/bin/env sh
 831→set -eu
 832→
 833→# Forge installer — downloads pre-built binary from GitHub Releases.
 834→# Usage: curl -sSf https://raw.githubusercontent.com/jdsingh122918/forge/main/install.sh | sh
 835→# Pin a version: FORGE_VERSION=v0.2.0 curl ... | sh
 836→
 837→REPO="jdsingh122918/forge"
 838→INSTALL_DIR="${HOME}/.forge/bin"
 839→
 840→main() {
 841→    detect_platform
 842→    get_version
 843→    download_and_verify
 844→    install_binary
 845→    configure_path
 846→    print_success
 847→}
 848→
 849→detect_platform() {
 850→    OS=$(uname -s)
 851→    ARCH=$(uname -m)
 852→
 853→    case "$OS" in
 854→        Darwin) ;;
 855→        Linux) ;;
 856→        *)
 857→            echo "Error: Unsupported OS: $OS"
 858→            echo "Forge supports macOS and Linux."
 859→            exit 1
 860→            ;;
 861→    esac
 862→
 863→    case "$ARCH" in
 864→        x86_64|amd64) ARCH="x86_64" ;;
 865→        arm64|aarch64) ARCH="aarch64" ;;
 866→        *)
 867→            echo "Error: Unsupported architecture: $ARCH"
 868→            exit 1
 869→            ;;
 870→    esac
 871→
 872→    case "${OS}-${ARCH}" in
 873→        Darwin-x86_64)  TARGET="x86_64-apple-darwin" ;;
 874→        Darwin-aarch64) TARGET="aarch64-apple-darwin" ;;
 875→        Linux-x86_64)   TARGET="x86_64-unknown-linux-gnu" ;;
 876→        Linux-aarch64)  TARGET="aarch64-unknown-linux-gnu" ;;
 877→        *)
 878→            echo "Error: Unsupported platform: ${OS}-${ARCH}"
 879→            exit 1
 880→            ;;
 881→    esac
 882→
 883→    echo "Detected platform: ${TARGET}"
 884→}
 885→
 886→get_version() {
 887→    if [ -n "${FORGE_VERSION:-}" ]; then
 888→        VERSION="$FORGE_VERSION"
 889→        echo "Installing pinned version: ${VERSION}"
 890→    else
 891→        echo "Fetching latest release..."
 892→        VERSION=$(curl -sSf "https://api.github.com/repos/${REPO}/releases/latest" \
 893→            | grep '"tag_name"' \
 894→            | sed 's/.*"tag_name": *"\([^"]*\)".*/\1/')
 895→
 896→        if [ -z "$VERSION" ]; then
 897→            echo "Error: Could not determine latest version."
 898→            echo "Check https://github.com/${REPO}/releases"
 899→            exit 1
 900→        fi
 901→        echo "Latest version: ${VERSION}"
 902→    fi
 903→}
 904→
 905→download_and_verify() {
 906→    ARCHIVE="forge-${TARGET}.tar.gz"
 907→    URL="https://github.com/${REPO}/releases/download/${VERSION}/${ARCHIVE}"
 908→    CHECKSUMS_URL="https://github.com/${REPO}/releases/download/${VERSION}/sha256sums.txt"
 909→
 910→    TMPDIR=$(mktemp -d)
 911→    trap 'rm -rf "$TMPDIR"' EXIT
 912→
 913→    echo "Downloading ${ARCHIVE}..."
 914→    curl -sSfL -o "${TMPDIR}/${ARCHIVE}" "$URL" || {
 915→        echo "Error: Failed to download ${URL}"
 916→        echo "Check that version ${VERSION} exists at https://github.com/${REPO}/releases"
 917→        exit 1
 918→    }
 919→
 920→    echo "Downloading checksums..."
 921→    curl -sSfL -o "${TMPDIR}/sha256sums.txt" "$CHECKSUMS_URL" || {
 922→        echo "Error: Failed to download checksums."
 923→        exit 1
 924→    }
 925→
 926→    echo "Verifying checksum..."
 927→    EXPECTED=$(grep "${ARCHIVE}" "${TMPDIR}/sha256sums.txt" | awk '{print $1}')
 928→    if [ -z "$EXPECTED" ]; then
 929→        echo "Error: Archive not found in checksums file."
 930→        exit 1
 931→    fi
 932→
 933→    if command -v sha256sum >/dev/null 2>&1; then
 934→        ACTUAL=$(sha256sum "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
 935→    elif command -v shasum >/dev/null 2>&1; then
 936→        ACTUAL=$(shasum -a 256 "${TMPDIR}/${ARCHIVE}" | awk '{print $1}')
 937→    else
 938→        echo "Warning: No sha256sum or shasum found, skipping verification."
 939→        ACTUAL="$EXPECTED"
 940→    fi
 941→
 942→    if [ "$EXPECTED" != "$ACTUAL" ]; then
 943→        echo "Error: Checksum verification failed!"
 944→        echo "  Expected: ${EXPECTED}"
 945→        echo "  Actual:   ${ACTUAL}"
 946→        exit 1
 947→    fi
 948→    echo "Checksum verified."
 949→
 950→    echo "Extracting..."
 951→    tar xzf "${TMPDIR}/${ARCHIVE}" -C "${TMPDIR}"
 952→}
 953→
 954→install_binary() {
 955→    mkdir -p "$INSTALL_DIR"
 956→    mv "${TMPDIR}/forge" "${INSTALL_DIR}/forge"
 957→    chmod +x "${INSTALL_DIR}/forge"
 958→    echo "Installed to ${INSTALL_DIR}/forge"
 959→}
 960→
 961→configure_path() {
 962→    case ":${PATH}:" in
 963→        *":${INSTALL_DIR}:"*) return ;; # Already in PATH
 964→    esac
 965→
 966→    EXPORT_LINE="export PATH=\"${INSTALL_DIR}:\$PATH\""
 967→    SHELL_NAME=$(basename "${SHELL:-/bin/sh}")
 968→
 969→    case "$SHELL_NAME" in
 970→        zsh)
 971→            RC_FILE="${HOME}/.zshrc"
 972→            ;;
 973→        bash)
 974→            # macOS uses .bash_profile for login shells
 975→            if [ "$(uname -s)" = "Darwin" ] && [ -f "${HOME}/.bash_profile" ]; then
 976→                RC_FILE="${HOME}/.bash_profile"
 977→            else
 978→                RC_FILE="${HOME}/.bashrc"
 979→            fi
 980→            ;;
 981→        fish)
 982→            FISH_CONFIG="${HOME}/.config/fish/config.fish"
 983→            if [ -f "$FISH_CONFIG" ] && ! grep -q "${INSTALL_DIR}" "$FISH_CONFIG" 2>/dev/null; then
 984→                echo "fish_add_path ${INSTALL_DIR}" >> "$FISH_CONFIG"
 985→                echo "Added ${INSTALL_DIR} to ${FISH_CONFIG}"
 986→            fi
 987→            return
 988→            ;;
 989→        *)
 990→            RC_FILE="${HOME}/.profile"
 991→            ;;
 992→    esac
 993→
 994→    if [ -f "$RC_FILE" ] && grep -qF "$INSTALL_DIR" "$RC_FILE" 2>/dev/null; then
 995→        return # Already configured
 996→    fi
 997→
 998→    echo "" >> "$RC_FILE"
 999→    echo "# Added by Forge installer" >> "$RC_FILE"
1000→    echo "$EXPORT_LINE" >> "$RC_FILE"
1001→    echo "Added ${INSTALL_DIR} to PATH in ${RC_FILE}"
1002→}
1003→
1004→print_success() {
1005→    VERSION_NUM=$("${INSTALL_DIR}/forge" --version 2>/dev/null | awk '{print $2}' || echo "${VERSION}")
1006→    echo ""
1007→    echo "Forge ${VERSION_NUM} installed successfully!"
1008→    echo ""
1009→    echo "To get started, run:"
1010→    echo "  source ${RC_FILE:-~/.profile}  # or open a new terminal"
1011→    echo "  forge --help"
1012→    echo ""
1013→}
1014→
1015→main
1016→```
