    #[test]
    fn test_version_is_semver() {
        let parts: Vec<&str> = VERSION.split('.').collect();
        assert_eq!(parts.len(), 3, "VERSION should be semver: {}", VERSION);
        for part in &parts {
            assert!(part.parse::<u64>().is_ok(), "Non-numeric version part: {}", part);
        }
    }
}
