  1→//! Background version check and update configuration.
  2→
  3→use anyhow::Result;
  4→use serde::{Deserialize, Serialize};
  5→use std::path::{Path, PathBuf};
  6→
  7→/// Update preferences from ~/.forge/config.toml [update] section.
  8→#[derive(Debug, Clone, Serialize, Deserialize)]
  9→pub struct UpdateConfig {
 10→    /// Silently auto-update on startup. Default: false.
 11→    #[serde(default)]
 12→    pub auto: bool,
 13→    /// Hours between version checks. Default: 24.
 14→    #[serde(default = "default_check_interval")]
 15→    pub check_interval: u64,
 16→}
 17→
 18→fn default_check_interval() -> u64 {
 19→    24
 20→}
 21→
 22→impl Default for UpdateConfig {
 23→    fn default() -> Self {
 24→        Self {
 25→            auto: false,
 26→            check_interval: default_check_interval(),
 27→        }
 28→    }
 29→}
 30→
 31→/// Cached result of the last version check.
 32→#[derive(Debug, Serialize, Deserialize)]
 33→pub struct UpdateCache {
 34→    /// Unix timestamp of last check.
 35→    pub timestamp: u64,
 36→    /// Latest version seen (without "v" prefix).
 37→    pub latest_version: String,
 38→}
 39→
 40→/// Returns the global forge config directory (~/.forge/).
 41→pub fn global_forge_dir() -> Result<PathBuf> {
 42→    let home = dirs::home_dir().ok_or_else(|| anyhow::anyhow!("Cannot determine home directory"))?;
 43→    Ok(home.join(".forge"))
 44→}
 45→
 46→/// Load update config from ~/.forge/config.toml.
 47→/// Returns defaults if file or [update] section is missing.
 48→pub fn load_update_config(forge_dir: &Path) -> Result<UpdateConfig> {
 49→    let config_path = forge_dir.join("config.toml");
 50→    if !config_path.exists() {
 51→        return Ok(UpdateConfig::default());
 52→    }
 53→    let content = std::fs::read_to_string(&config_path)?;
 54→    let table: toml::Table = content.parse()?;
 55→    match table.get("update") {
 56→        Some(section) => {
 57→            let config: UpdateConfig = section.clone().try_into()?;
 58→            Ok(config)
 59→        }
 60→        None => Ok(UpdateConfig::default()),
 61→    }
 62→}
 63→
 64→/// Read the update cache from ~/.forge/last-update-check.
 65→pub fn read_cache(forge_dir: &Path) -> Result<Option<UpdateCache>> {
 66→    let cache_path = forge_dir.join("last-update-check");
 67→    if !cache_path.exists() {
 68→        return Ok(None);
 69→    }
 70→    let content = std::fs::read_to_string(&cache_path)?;
 71→    let cache: UpdateCache = serde_json::from_str(&content)?;
 72→    Ok(Some(cache))
 73→}
 74→
 75→/// Write the update cache to ~/.forge/last-update-check.
 76→pub fn write_cache(forge_dir: &Path, cache: &UpdateCache) -> Result<()> {
 77→    let cache_path = forge_dir.join("last-update-check");
 78→    std::fs::create_dir_all(forge_dir)?;
 79→    let content = serde_json::to_string(cache)?;
 80→    std::fs::write(&cache_path, content)?;
 81→    Ok(())
 82→}
 83→
 84→/// Returns true if the cache is fresh (within check_interval hours).
 85→pub fn is_cache_fresh(cache: &UpdateCache, check_interval_hours: u64) -> bool {
 86→    let now = std::time::SystemTime::now()
 87→        .duration_since(std::time::UNIX_EPOCH)
 88→        .unwrap_or_default()
 89→        .as_secs();
 90→    let age_secs = now.saturating_sub(cache.timestamp);
 91→    age_secs < check_interval_hours * 3600
 92→}
 93→
 94→/// Compare two semver version strings. Returns true if `latest` is newer than `current`.
 95→pub fn is_newer(current: &str, latest: &str) -> bool {
 96→    let parse = |s: &str| -> Option<(u64, u64, u64)> {
 97→        let s = s.strip_prefix('v').unwrap_or(s);
 98→        let parts: Vec<&str> = s.split('.').collect();
 99→        if parts.len() != 3 {
100→            return None;
101→        }
102→        Some((
